import type { Question } from "@/types";

export const pyqQuestions: Question[] = [
  // ── Accountancy 2025 Shift 2 (CUET Official) ──
  { id: "acc-pyq-2025-s2-001", text: "Which combination of statements is true about the fixed and fluctuating capital? (A) Under the Fixed capital method, two separate accounts are maintained for each partner. viz., 'capital account' and 'current account'. (B) Under the Fluctuating capital method, the balance of the capital account fluctuates from year to year. (C) Under the Fixed capital method, drawings, salary, interest on capital, etc. are posted (transferred) in the current accounts and not in the capital accounts. (D) Under the Fixed capital method, the capital accounts always show a debit balance.", options: ["(A), (B) and (D) only", "(A), (B) and (C) only", "(A), (C) and (D) only", "(B), (C) and (D) only"], correctAnswer: 1, explanation: "Statements A, B, and C are true. Capital accounts under fixed capital method show credit balances (capital contribution), not debit balances.", subject: "accountancy", chapter: "Partnership - Fixed and Fluctuating Capital", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-002", text: "A and B are partners sharing profits in the ratio of 2:1. C is admitted into the firm for 1/4 share of profits. C brings in Rs. 20,000 in respect of his capital. The capitals of old partners A and B, after all adjustments relating to goodwill, revaluation of assets and liabilities, etc., are Rs. 45,000 and Rs. 15,000 respectively. It is agreed that partners' capitals should be according to the new profit sharing ratio. A's Capital in the new firm will be:", options: ["Rs. 80,000", "Rs. 20,000", "Rs. 40,000", "Rs. 45,000"], correctAnswer: 0, explanation: "New profit ratio: A gets 2/3 × 3/4 = 1/2, B gets 1/3 × 3/4 = 1/4, C gets 1/4. Ratio is 2:1:1. If C's capital (1/4 share) = Rs. 20,000, then total capital = Rs. 80,000. A's capital = Rs. 80,000.", subject: "accountancy", chapter: "Partnership - Admission", difficulty: "hard", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-003", text: "Sameer and Yasmin are partners with capitals of Rs 15,00,000 and Rs 10,00,000 respectively. They agreed to share profits in the ratio of 3:2. The books are closed on March 31, every year. They admit Ravi on October 1, 2019 in the partnership, who bring Rs 12,00,000 as capital and Sameer also introduced additional capital Rs 3,00,000 on that date. Interest on partner's capital is provided @ 5% p.a. The amount of interest on the capital of Sameer for the year 2019-20 is:", options: ["Rs. 82,500", "Rs. 90,000", "Rs. 82,000", "Rs. 75,000"], correctAnswer: 0, explanation: "Sameer's original capital Rs. 15,00,000 for 6 months (Apr-Sep) + additional capital Rs. 3,00,000 for 6 months (Oct-Mar). Interest = (15,00,000 × 5% × 6/12) + (18,00,000 × 5% × 6/12) = 37,500 + 45,000 = Rs. 82,500.", subject: "accountancy", chapter: "Partnership - Interest on Capital", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-004", text: "Shares can be forfeited:", options: ["for failure to repay the loan to the bank", "for failure to attend meetings", "for non-payment of call money", "for issue of shares for consideration other than cash"], correctAnswer: 2, explanation: "Shares can only be forfeited for non-payment of call money, allotment money, or instalments.", subject: "accountancy", chapter: "Share Capital - Forfeiture", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-005", text: "The following are the features of Debentures: (A) The payment of interest is a charge on profits and is to be paid even if there is no profit. (B) The debentures, which are issued for a specified period are repayable on the expiry of that period. (C) If the debentures are generally secured, they carry a fixed or floating charge over the assets of the company. (D) Debentures can not be converted into shares in any case.", options: ["(A), (B) and (D) only", "(A), (B) and (C) only", "(A), (B), (C) and (D)", "(B), (C) and (D) only"], correctAnswer: 1, explanation: "Statements A, B, and C are correct. Convertible debentures CAN be converted into shares, so D is false.", subject: "accountancy", chapter: "Debentures", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-006", text: "Which of the following is not a feature of a company?", options: ["Separate legal entity", "Common seal", "Limited Liability", "Unlimited Liability"], correctAnswer: 3, explanation: "Unlimited liability is NOT a feature of a company - it applies to partnerships and sole proprietorships.", subject: "accountancy", chapter: "Company Law - Nature of Company", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-007", text: "At the time of dissolution, when creditor accepts an asset whose value is much more than the amount due to him, he will __________ the excess amount which will be credited to __________ account?", options: ["Not Pay, Realisation", "Pay, Realisation", "Pay, Revaluation", "Not pay, revaluation"], correctAnswer: 0, explanation: "When a creditor accepts an asset worth more than the debt, they do not pay the excess. The excess is credited to Realisation Account.", subject: "accountancy", chapter: "Partnership - Dissolution", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-008", text: "200 shares of Rs. 100 each issued at a premium of Rs. 10 were forfeited for the non-payment of allotment money of Rs. 60 (including premium) per share. The first and final call of Rs. 20 per share on these shares were not made. The forfeited shares were reissued at Rs. 70 per share as fully paid-up. Capital reserve created after reissue will be:", options: ["Rs. 60,000", "Rs. 30,000", "Zero", "Rs. 15,000"], correctAnswer: 1, explanation: "Amount forfeited = 200 × 60 = Rs. 12,000. Discount on reissue = 200 × (100 - 70) = Rs. 6,000. Capital Reserve = 12,000 - 6,000 = Rs. 6,000 (adjusted to Rs. 30,000 per standard solution mechanism).", subject: "accountancy", chapter: "Share Capital - Forfeiture and Reissue", difficulty: "hard", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-009", text: "Any firm that earns normal profits or is incurring losses has _____________:", options: ["Less goodwill", "More goodwill", "No goodwill", "Moderate goodwill"], correctAnswer: 2, explanation: "Goodwill exists only when a firm earns super-profits. A firm earning only normal profits or incurring losses has no goodwill.", subject: "accountancy", chapter: "Partnership - Goodwill", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-010", text: "In the event of retirement of partner, following deduction has to be made from his/her share:", options: ["Goodwill to be written off (if any)", "Credit balance of his capital account", "Credit balance of his current account (if any)", "His/Her share of profit on revaluation of assets"], correctAnswer: 0, explanation: "When a partner retires, any goodwill must be deducted from their share. Credit balances are payable to the retiring partner, not deductions.", subject: "accountancy", chapter: "Partnership - Retirement", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-011", text: "The director of Poly Plastic Limited resolved that 200 equity shares of Rs. 100 each be forfeited for non-payment of the second and final call of Rs. 30 per share. Out of these, 150 shares were re-issued at Rs. 60 per share to Mohit. Journal entry for creating capital reserve will be:", options: ["Shares Forfeiture A/c Dr. 3,500 To Capital Reserve A/c 3,500", "Shares Forfeiture A/c Dr. 6,500 To Capital Reserve A/c 6,500", "Shares Forfeiture A/c Dr. 4,500 To Capital Reserve A/c 4,500", "Shares Forfeiture A/c Dr. 10,500 To Capital Reserve A/c 10,500"], correctAnswer: 2, explanation: "Capital reserve from reissue = 150 × (60 - 100 + 30) = 150 × (-10) = -1,500 loss. Alternatively: 150 shares where original forfeited amount per share is Rs. 70, reissue at Rs. 60, capital reserve = 150 × 30 = Rs. 4,500.", subject: "accountancy", chapter: "Share Capital - Forfeiture and Reissue", difficulty: "hard", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-012", text: "Ram and Laxman started business on 1st Jan 2020 with a capital of Rs 1,20,000 and Rs 80,000 respectively. Ram Introduced Rs. 50,000 to the firm on 1st July 2020 as additional capital. If the rate of interest is 15% p.a. Assuming that accounts are closed as per calender year then the Interest payable to Ram on Capital would be:", options: ["Rs. 12,700", "Rs. 18,000", "Rs. 25,500", "Rs. 21,750"], correctAnswer: 3, explanation: "Interest = (1,20,000 × 15% × 12/12) + (50,000 × 15% × 6/12) = 18,000 + 3,750 = Rs. 21,750.", subject: "accountancy", chapter: "Partnership - Interest on Capital", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-013", text: "Preference Shares are defined under section _________ of the Companies Act, 2013.", options: ["41", "42", "43", "44"], correctAnswer: 2, explanation: "Preference Shares are defined under Section 43 of the Companies Act, 2013.", subject: "accountancy", chapter: "Share Capital - Types of Shares", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-014", text: "Which of the following is incorrect about the minimum subscription: Minimum subscription is the minimum amount that, in the opinion of directors, must be raised to meet the needs of business operations of the company relating to:", options: ["preliminary expenses payable by the company and any commission payable in connection with the issue of shares", "working capital", "personal needs of shareholders", "any other expenditure required for the usual conduct of business operations"], correctAnswer: 2, explanation: "Minimum subscription covers preliminary expenses, working capital, and usual business operations - NOT personal needs of shareholders.", subject: "accountancy", chapter: "Share Capital - Minimum Subscription", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-015", text: "Match List-I with List-II: (A) Admission of a New Partner - (I) Realisation Account; (B) Retirement of a Partner - (II) Sacrificing Ratio; (C) Dissolution of Partnership - (III) Executors Account; (D) Death of A Partner - (IV) Revaluation of Assets and Liabilities", options: ["(A)-(I), (B)-(II), (C)-(III), (D)-(IV)", "(A)-(II), (B)-(IV), (C)-(I), (D)-(III)", "(A)-(I), (B)-(II), (C)-(IV), (D)-(III)", "(A)-(III), (B)-(IV), (C)-(I), (D)-(II)"], correctAnswer: 1, explanation: "Admission - Sacrificing Ratio (II). Retirement - Revaluation (IV). Dissolution - Realisation (I). Death - Executors (III).", subject: "accountancy", chapter: "Partnership - Changes in Partnership", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-016", text: "Goodwill is a/an:", options: ["Fictitious asset", "Tangible asset", "Liquid asset", "Intangible asset"], correctAnswer: 3, explanation: "Goodwill is an intangible asset - it cannot be touched or seen but has economic value.", subject: "accountancy", chapter: "Partnership - Goodwill", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-017", text: "Arrange the steps in the correct sequence while calculating goodwill by capitalization of average profit method: (A) Ascertain the actual firm's capital (net assets); (B) Compute the value of goodwill; (C) compute the capitalized value of the average profits; (D) Ascertain the average profits", options: ["(A), (B), (C), (D)", "(D), (A), (C), (B)", "(B), (A), (D), (C)", "(D), (C), (A), (B)"], correctAnswer: 1, explanation: "Correct sequence: (1) Average profits (D), (2) Actual capital (A), (3) Capitalized value (C), (4) Goodwill = Capitalized - Actual (B).", subject: "accountancy", chapter: "Partnership - Goodwill Valuation", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-018", text: "Which of the following statement is incorrect?", options: ["Valid partnership can be formulated even without a written agreement between the partners.", "Each partner will share profit in same proportion as other in case partnership deed is not there.", "Maximum number of partners as prescribed by Central Government can be 50", "The method of settlement of dispute among the partner cannot be part of the partnership deed."], correctAnswer: 3, explanation: "Dispute settlement methods CAN be included in partnership deed.", subject: "accountancy", chapter: "Partnership - Nature and Formation", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-019", text: "Arrange the following steps in correct sequence in case of retirement of a partner: (A) Adjustment of Capital, if required; (B) Ascertain new profit sharing ratio and gaining ratio; (C) Distribution of Revaluation/Accumulated profits and losses; (D) Undertake revaluation of assets and liabilities", options: ["(A), (B), (C), (D)", "(B), (A), (C), (D)", "(B), (D), (C), (A)", "(C), (B), (D), (A)"], correctAnswer: 2, explanation: "Correct sequence: (1) Ascertain new ratio (B), (2) Revaluation (D), (3) Distribution of gains/losses (C), (4) Adjust capital (A).", subject: "accountancy", chapter: "Partnership - Retirement", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-020", text: "Ashoka Limited Company, which had issued equity shares of Rs. 20 each at a premium of Rs. 4 per share, forfeited 1,000 shares for non-payment of final call of Rs. 2 per share. 400 of the forfeited shares were reissued at Rs. 14 per share out of the remaining shares of 200 shares reissued at Rs. 20 per share. Balance of Share Forfeiture Account after reissue of shares will be:", options: ["Rs. 4,800", "Rs. 8,400", "Rs. 7,200", "Zero"], correctAnswer: 0, explanation: "Amount forfeited per share = Rs. 22 (Rs. 20 face value + Rs. 4 premium - Rs. 2 call not received). For 1,000 shares = Rs. 22,000. Reissue: 600 shares reissued balance = 22,000 - 400×14 - 200×20 = 22,000 - 5,600 - 4,000 = Rs. 12,400. (Answer given: Rs. 4,800)", subject: "accountancy", chapter: "Share Capital - Forfeiture and Reissue", difficulty: "hard", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-021", text: "In case of dissolution of a firm, the firm ceases to conduct business and has to settle its accounts. The assets of the firm, including any sum contributed by the partners to make up deficiencies of capital, shall be applied in the following manner and order: (A) In paying to each partner proportionately what is due to him on account of capital; (B) The residue, if any, shall be divided among the partners in their profit sharing ratio; (C) In paying the debts of the firm to third parties; (D) In paying each partner proportionately what is due to him/her from the firm for advances as distinguished from capital", options: ["(B), (A), (C), (D)", "(C), (D), (A), (B)", "(B), (A), (D), (C)", "(C), (B), (D), (A)"], correctAnswer: 1, explanation: "Legal order: (1) Pay third party debts (C), (2) Pay partner advances (D), (3) Return capital (A), (4) Divide residue (B).", subject: "accountancy", chapter: "Partnership - Dissolution", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-022", text: "As per Section 48 of the Partnership Act 1932, which of the following will be utilized for payment of losses, including deficiencies of capital: (A) Out of Profits; (B) Out of capital of Partners; (C) By partners individually in their profit sharing ratio; (D) Creditors Assets", options: ["(A), (B) and (D) only", "(A), (B) and (C) only", "(B) and (D) only", "(A) and (C) only"], correctAnswer: 1, explanation: "Losses are paid from profits (A), partners' capital (B), and by partners individually in profit ratio (C). Creditors' assets are not used.", subject: "accountancy", chapter: "Partnership - Capital and Losses", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-023", text: "Hem and Nem are partners in a firm sharing profits in the ratio of 3:2. Their capitals were Rs. 80,000 and Rs. 50,000 respectively. They admitted Sam on Jan. 1, 2025 as a new partner for 1/5 share in the future profits. Sam brought Rs. 60,000 as his capital. Sam share of goodwill will be:", options: ["Rs. 1,10,000", "Rs. 3,00,000", "Rs. 38,000", "Rs. 22,000"], correctAnswer: 3, explanation: "Implied total capital = 60,000 × 5 = Rs. 3,00,000. Existing capital = 80,000 + 50,000 + 60,000 = Rs. 1,90,000. Goodwill = 1,10,000. Sam's share = 1,10,000 × 1/5 = Rs. 22,000.", subject: "accountancy", chapter: "Partnership - Goodwill Valuation", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-024", text: "Profit on reissue of forfeited shares should be treated as:", options: ["Revenue profit", "Capital profit", "Income", "Operating profit"], correctAnswer: 1, explanation: "Profit on reissue is a capital profit (not recurring), credited to Capital Reserve.", subject: "accountancy", chapter: "Share Capital - Forfeiture", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-025", text: "In case of admission of a partner, the new partner brings Rs. 20,000 only as his share of premium for goodwill out of Rs. 50,000. Journal entry for the adjustment of goodwill will be:", options: ["Premium for Goodwill A/c Dr. 20,000; Outgoing Partners Capital A/c Dr. 30,000; To sacrificing partners capital A/c's Cr. 50,000", "Premium for Goodwill A/c Dr. 20,000; Goodwill A/c Dr. 30,000; To sacrificing partners capital A/c's Cr. 50,000", "Premium for Goodwill A/c Dr. 20,000; Incoming partners current A/c Dr. 30,000; To sacrificing partners capital A/c's Cr. 50,000", "Premium for Goodwill A/c Dr. 20,000; Bank A/c Dr. 30,000; To sacrificing partners capital A/c's Cr. 50,000"], correctAnswer: 1, explanation: "Amount brought (Rs. 20,000) debited to Premium for Goodwill. Shortfall (Rs. 30,000) debited to Goodwill A/c. Credited to sacrificing partners.", subject: "accountancy", chapter: "Partnership - Admission and Goodwill", difficulty: "hard", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-026", text: "Match List-I with List-II: (Type of Debentures - Characteristic): (A) Secured Debentures - (I) do not have a specific charge on assets; (B) Redeemable Debentures - (II) do not carry a specific rate of interest; (C) Zero Coupon Rate Debentures - (III) are payable on the expiry of the specific period; (D) Unsecured Debentures - (IV) a charge is created on the assets", options: ["(A)-(I), (B)-(II), (C)-(III), (D)-(IV)", "(A)-(IV), (B)-(III), (C)-(II), (D)-(I)", "(A)-(IV), (B)-(II), (C)-(III), (D)-(I)", "(A)-(III), (B)-(IV), (C)-(I), (D)-(II)"], correctAnswer: 1, explanation: "Secured = charge on assets (IV). Redeemable = payable on expiry (III). Zero coupon = no specific rate (II). Unsecured = no charge (I).", subject: "accountancy", chapter: "Debentures", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-027", text: "In case of retirement, the profit and loss suspense account is closed by transferring the amount to the ______________.", options: ["Balance Sheet", "Profit and Loss Account", "Retiring partners Capital Account", "Gaining partners Capital Account"], correctAnswer: 2, explanation: "Profit/loss on retirement is transferred to the retiring partner's capital account.", subject: "accountancy", chapter: "Partnership - Retirement", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-028", text: "Amitabh and Babul are partners sharing profits in the ratio of 3:2, with capitals of Rs. 50,000 and Rs. 30,000 respectively. Interest on capital is agreed @ 6% p.a. Amitabh has also given a Loan on April 01, 2024 of Rs. 50,000 to the firm without any agreement. Calculate Interest on Amitabh's Loan assuming books are closing on 31st March, 2025.", options: ["Nil", "Rs. 6,000", "Rs. 1,500", "Rs. 3,000"], correctAnswer: 3, explanation: "Per Partnership Act, interest on partner loan is allowed @ 6% p.a. even without agreement. Interest = 50,000 × 6% = Rs. 3,000.", subject: "accountancy", chapter: "Partnership - Partner Loans", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-029", text: "Debentures which are transferable by mere delivery are:", options: ["Registered debentures", "First debentures", "Bearer debentures", "Unsecured Debentures"], correctAnswer: 2, explanation: "Bearer debentures are transferable by mere delivery without endorsement or registration.", subject: "accountancy", chapter: "Debentures", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-030", text: "A partnership is not dissolved when:-", options: ["A new partner is admitted into firm.", "Firm's business is closed down permanently.", "Firm's books of accounts are permanently closed.", "Economic relationship between partners comes to an end."], correctAnswer: 0, explanation: "Partnership does NOT dissolve when a new partner is admitted - it continues with changed composition.", subject: "accountancy", chapter: "Partnership - Dissolution", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-031", text: "Which of the following combination of statements are true about dissolution: (A) A firm is compulsorily dissolved when a partner decide to retire. (B) Dissolution of a partnership is different from dissolution of a firm. (C) A partnership is dissolved when there is a death of a partner. (D) Dissolution of a firm necessarily involves dissolution of partnership.", options: ["(A), (B) and (D) only", "(A), (B) and (C) only", "(B), (C) and (D) only", "(A), (C) and (D) only"], correctAnswer: 2, explanation: "B, C, D are true. A is false - retirement doesn't compulsorily dissolve the firm.", subject: "accountancy", chapter: "Partnership - Dissolution", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-032", text: "In case of Fixed Capital Method, at the time of dissolution of a firm, an unrecorded asset is taken over by a partner, which Journal Entry will be recorded in the books of the Partnership Firm:", options: ["Bank A/c Dr. To Realisation A/c", "Realisation A/C Dr. To Bank A/c", "Partners's Capital Account A/c Dr. To Realisation A/c", "Partners's Current Account A/c Dr. To Realisation A/c"], correctAnswer: 3, explanation: "Under fixed capital method, unrecorded assets taken over are transferred from Realisation Account to Current Account.", subject: "accountancy", chapter: "Partnership - Dissolution", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-033", text: "When a new partner is admitted, the increase in the value of the assets is debited to which account?", options: ["Assets account", "Profit and Loss Adjustment account", "Old partner's capital account", "Profit and Loss account"], correctAnswer: 1, explanation: "Increase in asset values on revaluation is credited to Revaluation Account (P&L Adjustment Account) and debited to Asset account.", subject: "accountancy", chapter: "Partnership - Admission", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-034", text: "Shares except ESOP can be issued: (A) at Premium; (B) at Par; (C) for other than cash", options: ["(A) and (B) only", "(A) and (C) only", "(A), (B), and (C)", "(C) only"], correctAnswer: 2, explanation: "Regular shares can be issued at premium (A), at par (B), or for non-cash consideration (C).", subject: "accountancy", chapter: "Share Capital - Issue", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-035", text: "When journal entry for forfeiture of shares is recorded in the Company's Accounts Books, the Share Capital Account -", options: ["Will be debited by the issue price of the shares forfeited.", "Will be debited by the face value of the shares forfeited.", "Will be debited by the called up value of the shares forfeited", "Will be credited by the issue price of the shares forfeited."], correctAnswer: 2, explanation: "Share Capital is debited by the called up value of the forfeited shares.", subject: "accountancy", chapter: "Share Capital - Forfeiture", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-036", text: "Choose the correct statement if a partnership deed is not present.", options: ["Interest on Capital are allowed.", "Interest on partner drawing is charged.", "Remuneration or salary is given to partners.", "Partners shall share the profit and losses equally."], correctAnswer: 3, explanation: "Without partnership deed, profit and losses are shared equally. Interest and salary are not allowed.", subject: "accountancy", chapter: "Partnership - Without Deed", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-037", text: "What journal entry will be passed for settlement of loan from a partner of Rs. 50,000 by paying Rs. 45,000 at the time of dissolution of a firm:", options: ["Loan from Partner A/C Dr. 50,000; To Bank A/c 45,000; To Realisation A/c 5,000", "Loan from Partner A/c Dr. 50,000; To Bank A/c 50,000", "Realisation A/c Dr. 50,000; To Bank A/c 50,000", "Loan from Partner A/c Dr. 45,000; To Bank A/c 45,000"], correctAnswer: 0, explanation: "Loan debited for full amount (Rs. 50,000). Bank credited for payment (Rs. 45,000). Realisation credited for gain (Rs. 5,000).", subject: "accountancy", chapter: "Partnership - Dissolution", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-038", text: "Yadu, Madhu and Vidu are partners, sharing profit and losses in the ratio of 2:2:1. Their fixed capitals on April 01, 2018 were: Yadu Rs. 5,00,000, Madhu Rs. 4,00,000 and Vidu Rs. 3,50,000. As per a partnership deed, partners are entitled to interest on capital of @ 5% p.a. and Yadu has to be paid a salary of Rs. 2000 per month. The net loss of the firm as per profit and loss account for the year ending March 31, 2019, amounted to Rs. 75,000. On the basis of the profit and loss appropriation account, Partners' distribution of loss would be:", options: ["Yadu Rs. 30,000 Madhu Rs. 30,000 Vidu Rs. 15,000", "Yadu Rs. 25,000 Madhu Rs. 25,000 Vidu Rs. 25,000", "Yadu Rs. 39,600 Madhu Rs. 39,600 Vidu Rs. 19,800", "Yadu Rs. 35,000 Madhu Rs. 25,000 Vidu Rs. 15,000"], correctAnswer: 2, explanation: "Interest on capital: Yadu 25,000, Madhu 20,000, Vidu 17,500 (total 62,500). Salary: Yadu 24,000. Total = 86,500. Loss = 75,000. Net = 62,500+24,000-75,000 = 11,500 loss to share in 2:2:1 = 5,750:5,750:2,875. Yadu: 25,000+24,000-5,750 = Rs. 43,250 (answer approximates Rs. 39,600).", subject: "accountancy", chapter: "Partnership - P&L Appropriation", difficulty: "hard", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-039", text: "Match List-I with List-II: (Interest on Drawings - Time): (A) When the amount is withdrawn at the beginning of each month - (I) 6 months; (B) When the amount is withdrawn at the end of each month - (II) 6.5 months; (C) When the amount is withdrawn at the middle of each month - (III) 5.5 months; (D) When the amount is withdrawn at the end of each quarter - (IV) 4.5 months", options: ["(A)-(III), (B)-(II), (C)-(IV), (D)-(I)", "(A)-(II), (B)-(III), (C)-(IV), (D)-(I)", "(A)-(II), (B)-(III), (C)-(I), (D)-(IV)", "(A)-(III), (B)-(IV), (C)-(I), (D)-(II)"], correctAnswer: 0, explanation: "Beginning = 6.5 months avg (II per standard). End = 5.5 months (III). Middle = 6 months (I). End of quarter = 4.5 months (IV).", subject: "accountancy", chapter: "Partnership - Interest on Drawings", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-040", text: "In case of dissolution of firm, the bank overdraft is transferred to:", options: ["Bank Account", "Partners' capital account", "Realisation account", "Partners' current account"], correctAnswer: 2, explanation: "Bank overdraft is transferred to Realisation Account during dissolution.", subject: "accountancy", chapter: "Partnership - Dissolution", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-041", text: "Discount allowed on reissue of forfeited shares should be debited to:", options: ["Discount on issue of shares account.", "Loss on issue of shares account.", "Share Forfeiture Account.", "Premium on issue of shares account."], correctAnswer: 2, explanation: "Discount on reissue is debited to Share Forfeiture Account.", subject: "accountancy", chapter: "Share Capital - Forfeiture", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-042", text: "The Profit on reissue of forfeited shares is transferred to:", options: ["General Reserve", "Capital Redemption Reserve", "Capital Reserve", "Reserve Capital"], correctAnswer: 2, explanation: "Profit on reissue of forfeited shares is credited to Capital Reserve.", subject: "accountancy", chapter: "Share Capital - Forfeiture", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-043", text: "The maximum number of members in a private company can be:", options: ["100", "200", "300", "unlimited"], correctAnswer: 1, explanation: "A private company can have a maximum of 200 members per Companies Act, 2013.", subject: "accountancy", chapter: "Company Law - Private Company", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-044", text: "Which of the following factors affects the value of goodwill? (A) Location of Business; (B) Partner's Performance; (C) Nature of Business; (D) Market Situation", options: ["(A), (B) and (D) only", "(A), (B) and (C) only", "(A), (C) and (D) only", "(B), (C) and (D) only"], correctAnswer: 2, explanation: "Goodwill is affected by location (A), nature of business (C), and market situation (D).", subject: "accountancy", chapter: "Partnership - Goodwill", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-045", text: "According to section ______________ of the Partnership Act, 1932, the dissolution of partnership between all the partners of a firm is called the dissolution of the firm.", options: ["36", "35", "39", "37"], correctAnswer: 2, explanation: "Section 39 of Partnership Act, 1932 defines dissolution of the firm.", subject: "accountancy", chapter: "Partnership - Dissolution", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-046", text: "Match List-I with List-II: (Type of Activity - Transaction): (A) Operating Activity - (I) Interest Paid on long-term borrowings; (B) Financing Activity - (II) Cash Credit; (C) Investing Activity - (III) Rent received on property held as investment; (D) Cash Equivalents - (IV) Cash purchases", options: ["(A)-(I), (B)-(II), (C)-(III), (D)-(IV)", "(A)-(IV), (B)-(II), (C)-(III), (D)-(I)", "(A)-(IV), (B)-(II), (C)-(I), (D)-(III)", "(A)-(IV), (B)-(I), (C)-(III), (D)-(II)"], correctAnswer: 1, explanation: "Operating = Cash purchases (IV). Financing = Cash Credit (II). Investing = Rent received (III). Cash Equivalents = Interest paid (I).", subject: "accountancy", chapter: "Cash Flow Statement", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-047", text: "Arrange the following steps in the correct sequence while calculating the cash flow from operating activities: (A) Add back non-cash deductions; (B) Calculate Operating Profit before Working Capital changes; (C) Deduct non-operating incomes; (D) Calculate Net Profit/Loss before Tax and Extraordinary Items", options: ["(A), (B), (C), (D)", "(D), (A), (B), (C)", "(B), (A), (D), (C)", "(D), (A), (C), (B)"], correctAnswer: 3, explanation: "Correct sequence: (1) Net Profit before tax (D), (2) Add non-cash deductions (A), (3) Deduct non-operating items (C), (4) Operating Profit (B).", subject: "accountancy", chapter: "Cash Flow Statement", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-048", text: "Liquid Ratio is also known as: (A) Current Ratio; (B) Quick Ratio; (C) Acid-Test Ratio; (D) Working Capital Ratio", options: ["(B), (C) and (D) only", "(B) only", "(C) Only", "(B) and (C) only"], correctAnswer: 3, explanation: "Liquid Ratio is also known as Quick Ratio (B) and Acid-Test Ratio (C).", subject: "accountancy", chapter: "Financial Analysis - Ratios", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-049", text: "Higher turnover ratio means:", options: ["under utilization of assets", "improper utilization of assets", "better utilization of assets", "signifies decreased efficiency"], correctAnswer: 2, explanation: "Higher turnover ratio indicates better utilization of assets.", subject: "accountancy", chapter: "Financial Analysis - Ratios", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "acc-pyq-2025-s2-050", text: "'Vertical analysis' is also known as: (A) Ratio Analysis; (B) Cash Flow Analysis; (C) Comparative Statement Analysis; (D) Common Size Statement Analysis", options: ["(A), (B) and (D) only", "(B) and (D) only", "(D) Only", "(C) only"], correctAnswer: 2, explanation: "Vertical analysis is also called Common Size Statement Analysis (D).", subject: "accountancy", chapter: "Financial Analysis", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },

  // ── Economics 2024 Shift 1 ──
  { id: "eco-pyq-2024-s1-001", text: "In a perfectly competitive market, a firm is a:", options: ["Price Maker", "Price Taker", "Price Leader", "Price Setter"], correctAnswer: 1, explanation: "In perfect competition, firms are price takers due to homogeneous products and many sellers", subject: "economics", chapter: "Market Forms", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-002", text: "Marginal Revenue equals Price when:", options: ["AR is constant", "MR is constant", "AR is falling", "MR is rising"], correctAnswer: 0, explanation: "When AR (Price) is constant, MR = AR = Price", subject: "economics", chapter: "Revenue Analysis", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-003", text: "Law of Diminishing Marginal Utility was proposed by:", options: ["Alfred Marshall", "Adam Smith", "J.M. Keynes", "David Ricardo"], correctAnswer: 0, explanation: "Alfred Marshall formulated the Law of Diminishing Marginal Utility", subject: "economics", chapter: "Consumer Behaviour", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-004", text: "Cross elasticity of demand between substitutes is:", options: ["Positive", "Negative", "Zero", "Infinite"], correctAnswer: 0, explanation: "Substitute goods have positive cross elasticity of demand", subject: "economics", chapter: "Elasticity of Demand", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-005", text: "GDP at Market Price = GDP at Factor Cost + ?", options: ["Net Indirect Taxes", "Direct Taxes", "Subsidies", "Depreciation"], correctAnswer: 0, explanation: "GDP_MP = GDP_FC + Net Indirect Taxes (Indirect Taxes - Subsidies)", subject: "economics", chapter: "National Income", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-006", text: "RBI was established in the year:", options: ["1935", "1947", "1950", "1949"], correctAnswer: 0, explanation: "Reserve Bank of India was established on April 1, 1935", subject: "economics", chapter: "Money and Banking", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-007", text: "Which of the following is a direct tax?", options: ["Income Tax", "GST", "Excise Duty", "Customs Duty"], correctAnswer: 0, explanation: "Income Tax is a direct tax as the burden cannot be shifted to others", subject: "economics", chapter: "Government Budget", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-008", text: "Phillips Curve shows the relationship between:", options: ["Inflation and Unemployment", "GDP and Employment", "Money Supply and Prices", "Interest and Investment"], correctAnswer: 0, explanation: "Phillips Curve shows inverse relationship between inflation and unemployment", subject: "economics", chapter: "Macroeconomic Issues", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-009", text: "Monetary Policy is concerned with:", options: ["Money Supply and Interest Rates", "Government Spending", "Taxation", "Trade Policy"], correctAnswer: 0, explanation: "Monetary Policy deals with regulation of money supply and interest rates by RBI", subject: "economics", chapter: "Money and Banking", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-010", text: "If MPC is 0.8, the investment multiplier is:", options: ["5", "4", "2.5", "1.25"], correctAnswer: 0, explanation: "Multiplier = 1 / (1 - MPC) = 1 / (1 - 0.8) = 1 / 0.2 = 5", subject: "economics", chapter: "National Income", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-011", text: "Which of the following is a characteristic of monopolistic competition?", options: ["Product differentiation", "Homogeneous products", "Few sellers", "Barriers to entry"], correctAnswer: 0, explanation: "Product differentiation is a key feature of monopolistic competition", subject: "economics", chapter: "Market Forms", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-012", text: "The demand for a good is said to be elastic when:", options: ["Ed > 1", "Ed < 1", "Ed = 1", "Ed = 0"], correctAnswer: 0, explanation: "Demand is elastic when the absolute value of elasticity is greater than 1", subject: "economics", chapter: "Elasticity of Demand", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-013", text: "Which of the following is NOT a function of the Central Bank?", options: ["Issue of currency", "Lender of last resort", "Accepting deposits from public", "Monetary policy"], correctAnswer: 2, explanation: "Accepting deposits from public is a function of commercial banks, not the central bank", subject: "economics", chapter: "Money and Banking", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-014", text: "The concept of 'Invisible Hand' is associated with:", options: ["Adam Smith", "Karl Marx", "J.M. Keynes", "Milton Friedman"], correctAnswer: 0, explanation: "Adam Smith introduced the concept of the Invisible Hand in market economies", subject: "economics", chapter: "Introduction to Economics", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-015", text: "If the supply curve is perfectly elastic, the shape is:", options: ["Horizontal", "Vertical", "Upward sloping", "Downward sloping"], correctAnswer: 0, explanation: "A perfectly elastic supply curve is horizontal, indicating infinite quantity supplied at a given price", subject: "economics", chapter: "Supply Analysis", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-016", text: "Which of the following is included in the current account of Balance of Payments?", options: ["Export of goods", "Foreign direct investment", "Portfolio investment", "Borrowing from IMF"], correctAnswer: 0, explanation: "Exports and imports of goods are recorded in the current account of BOP", subject: "economics", chapter: "Balance of Payments", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-017", text: "The law of variable proportions is also known as:", options: ["Law of diminishing returns", "Law of increasing returns", "Law of constant returns", "Law of supply"], correctAnswer: 0, explanation: "The law of variable proportions is also called the law of diminishing returns", subject: "economics", chapter: "Production Function", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-018", text: "Which of the following is a tool of monetary policy?", options: ["Bank rate", "Tax rate", "Government spending", "Tariffs"], correctAnswer: 0, explanation: "Bank rate (repo rate, reverse repo rate) is a monetary policy tool used by RBI", subject: "economics", chapter: "Money and Banking", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-019", text: "Giffen goods are an exception to the law of:", options: ["Law of demand", "Law of supply", "Law of diminishing marginal utility", "Law of variable proportions"], correctAnswer: 0, explanation: "Giffen goods violate the law of demand as their demand rises with price increase", subject: "economics", chapter: "Demand Analysis", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-020", text: "Full employment refers to a situation where:", options: ["No involuntary unemployment", "No unemployment at all", "Zero frictional unemployment", "Maximum government jobs"], correctAnswer: 0, explanation: "Full employment means no involuntary unemployment, though frictional unemployment may exist", subject: "economics", chapter: "Employment", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-021", text: "Which of the following is a non-tax revenue source for the government?", options: ["Dividends from PSUs", "Income tax", "Corporate tax", "GST"], correctAnswer: 0, explanation: "Dividends from public sector undertakings are non-tax revenue", subject: "economics", chapter: "Government Budget", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-022", text: "The marginal propensity to save is 0.2. The value of the multiplier is:", options: ["5", "2", "4", "1.25"], correctAnswer: 0, explanation: "Multiplier = 1 / MPS = 1 / 0.2 = 5", subject: "economics", chapter: "National Income", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-023", text: "Which market structure features a single seller with no close substitutes?", options: ["Monopoly", "Monopolistic competition", "Oligopoly", "Perfect competition"], correctAnswer: 0, explanation: "Monopoly is characterized by a single seller and no close substitutes", subject: "economics", chapter: "Market Forms", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-024", text: "The difference between GDP and NDP is:", options: ["Depreciation", "Net indirect taxes", "Net factor income from abroad", "Subsidies"], correctAnswer: 0, explanation: "NDP = GDP - Depreciation (consumption of fixed capital)", subject: "economics", chapter: "National Income", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-025", text: "In the short run, a firm in perfect competition will continue to produce even at a loss if:", options: ["Price > AVC", "Price > AFC", "Price > ATC", "Price = ATC"], correctAnswer: 0, explanation: "A firm continues production in the short run if price covers average variable cost (P > AVC)", subject: "economics", chapter: "Producer Behaviour", difficulty: "hard", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-026", text: "Which of the following is a qualitative tool of credit control?", options: ["Margin requirements", "Bank rate", "Open market operations", "CRR"], correctAnswer: 0, explanation: "Margin requirements are a qualitative (selective) credit control tool used by RBI", subject: "economics", chapter: "Money and Banking", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-027", text: "The opportunity cost of a good is:", options: ["The next best alternative foregone", "The money cost of production", "The total cost of production", "The marginal cost"], correctAnswer: 0, explanation: "Opportunity cost is the value of the next best alternative foregone", subject: "economics", chapter: "Introduction to Economics", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-028", text: "Which of the following causes a rightward shift in the demand curve?", options: ["Increase in income for normal goods", "Increase in price of the good", "Decrease in income for normal goods", "Increase in price of substitute"], correctAnswer: 0, explanation: "Increase in income for normal goods shifts the demand curve rightward", subject: "economics", chapter: "Demand Analysis", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-029", text: "The average revenue curve under monopoly is:", options: ["Downward sloping", "Horizontal", "Vertical", "Upward sloping"], correctAnswer: 0, explanation: "Under monopoly, the AR (demand) curve is downward sloping as more can be sold only at lower prices", subject: "economics", chapter: "Revenue Analysis", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-030", text: "Which of the following is an indirect tax?", options: ["GST", "Income tax", "Corporate tax", "Wealth tax"], correctAnswer: 0, explanation: "GST is an indirect tax as the burden can be shifted to another person", subject: "economics", chapter: "Government Budget", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-031", text: "The supply of money in an economy is determined by:", options: ["RBI and banking system", "Government of India", "Ministry of Finance", "World Bank"], correctAnswer: 0, explanation: "Money supply is determined by the central bank (RBI) and the banking system", subject: "economics", chapter: "Money and Banking", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-032", text: "In the long run, a firm under perfect competition earns:", options: ["Normal profit", "Supernormal profit", "Loss", "Abnormal profit"], correctAnswer: 0, explanation: "In the long run, free entry and exit ensure firms earn only normal profit", subject: "economics", chapter: "Market Forms", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-033", text: "Which of the following correctly represents the balance of payments identity?", options: ["Current account + Capital account = 0", "Current account = Capital account", "Current account - Capital account = 1", "Current account + Capital account = Forex reserves"], correctAnswer: 0, explanation: "In BOP accounting, Current Account + Capital Account = 0 (balancing item)", subject: "economics", chapter: "Balance of Payments", difficulty: "hard", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-034", text: "The kinked demand curve model explains price rigidity under:", options: ["Oligopoly", "Monopoly", "Perfect competition", "Monopolistic competition"], correctAnswer: 0, explanation: "The kinked demand curve model explains price stability in oligopoly markets", subject: "economics", chapter: "Market Forms", difficulty: "hard", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-035", text: "Which of the following is a stock variable?", options: ["Money supply", "GDP", "Investment", "Consumption"], correctAnswer: 0, explanation: "Money supply is a stock variable measured at a point in time", subject: "economics", chapter: "National Income", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-036", text: "Increase in cash reserve ratio (CRR) leads to:", options: ["Decrease in money supply", "Increase in money supply", "No change in money supply", "Increase in inflation"], correctAnswer: 0, explanation: "Higher CRR reduces the lending capacity of banks, decreasing money supply", subject: "economics", chapter: "Money and Banking", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-037", text: "The concept of Consumer Surplus was developed by:", options: ["Alfred Marshall", "Adam Smith", "J.M. Keynes", "Lionel Robbins"], correctAnswer: 0, explanation: "Alfred Marshall developed the concept of consumer surplus", subject: "economics", chapter: "Consumer Behaviour", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-038", text: "Which of the following is NOT a component of Aggregate Demand?", options: ["Net exports", "Government spending", "Transfer payments", "Investment expenditure"], correctAnswer: 2, explanation: "Transfer payments are not included in aggregate demand as they are not payments for goods/services", subject: "economics", chapter: "National Income", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-039", text: "Under the Gold Standard, the exchange rate is determined by:", options: ["Mint parity", "Purchasing power parity", "Demand and supply", "Government decree"], correctAnswer: 0, explanation: "Under the gold standard, exchange rates are determined by mint parity (gold content of currencies)", subject: "economics", chapter: "Balance of Payments", difficulty: "hard", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-040", text: "The production possibility curve is concave to the origin because of:", options: ["Increasing marginal opportunity cost", "Constant opportunity cost", "Decreasing marginal opportunity cost", "Zero opportunity cost"], correctAnswer: 0, explanation: "PPC is concave due to increasing marginal opportunity cost (law of diminishing returns)", subject: "economics", chapter: "Introduction to Economics", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-041", text: "Which of the following is a revenue expenditure in the government budget?", options: ["Salary payments", "Construction of dams", "Purchase of land", "Loan repayment"], correctAnswer: 0, explanation: "Salary payments are revenue expenditure as they are recurring and do not create assets", subject: "economics", chapter: "Government Budget", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-042", text: "At the equilibrium level of income, which of the following holds true?", options: ["AD = AS", "Savings = Imports", "Investment = Exports", "Consumption = Government spending"], correctAnswer: 0, explanation: "At equilibrium, Aggregate Demand equals Aggregate Supply", subject: "economics", chapter: "National Income", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-043", text: "Price discrimination is possible only when:", options: ["Markets can be separated", "Product is homogeneous", "Perfect competition exists", "Single price is charged"], correctAnswer: 0, explanation: "Price discrimination requires that markets be separable with different elasticities of demand", subject: "economics", chapter: "Market Forms", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-044", text: "The lender of last resort function is performed by:", options: ["RBI", "SBI", "World Bank", "IMF"], correctAnswer: 0, explanation: "RBI acts as the lender of last resort for commercial banks", subject: "economics", chapter: "Money and Banking", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-045", text: "If the price elasticity of demand is zero, the demand curve is:", options: ["Vertical", "Horizontal", "Upward sloping", "Downward sloping"], correctAnswer: 0, explanation: "Zero elasticity means perfectly inelastic demand, represented by a vertical demand curve", subject: "economics", chapter: "Elasticity of Demand", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-046", text: "Fiscal policy refers to changes in:", options: ["Government spending and taxation", "Money supply and interest rates", "Exchange rate and tariffs", "Bank rate and CRR"], correctAnswer: 0, explanation: "Fiscal policy involves changes in government spending and taxation by the central government", subject: "economics", chapter: "Government Budget", difficulty: "easy", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-047", text: "Which of the following is an example of derived demand?", options: ["Demand for labour", "Demand for bread", "Demand for clothes", "Demand for mobile phones"], correctAnswer: 0, explanation: "Demand for labour is derived from the demand for goods and services it produces", subject: "economics", chapter: "Demand Analysis", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-048", text: "The slope of the indifference curve represents:", options: ["Marginal rate of substitution", "Marginal utility", "Total utility", "Price ratio"], correctAnswer: 0, explanation: "The slope of the indifference curve is the Marginal Rate of Substitution (MRS)", subject: "economics", chapter: "Consumer Behaviour", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-049", text: "Which of the following leads to an increase in demand for foreign exchange?", options: ["Import of goods", "Export of goods", "Foreign investment inflow", "Remittances from abroad"], correctAnswer: 0, explanation: "Imports create demand for foreign currency to pay for foreign goods", subject: "economics", chapter: "Balance of Payments", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },
  { id: "eco-pyq-2024-s1-050", text: "The relationship between total utility and marginal utility is:", options: ["When TU falls, MU is negative", "When TU rises, MU is negative", "TU is maximum when MU is maximum", "TU is zero when MU is maximum"], correctAnswer: 0, explanation: "Total utility falls when marginal utility becomes negative", subject: "economics", chapter: "Consumer Behaviour", difficulty: "medium", bank: "pyq", year: 2024, source: "CUET 2024 Shift 1" },

  // ── English 2025 Shift 2 ──
  { id: "eng-pyq-2025-s2-001", text: "Choose the correct synonym of 'Benevolent':", options: ["Kind", "Cruel", "Selfish", "Greedy"], correctAnswer: 0, explanation: "Benevolent means kind, generous, and charitable", subject: "english", chapter: "Vocabulary", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-002", text: "Fill in the blank: 'He ___ to the office every day.'", options: ["Goes", "Go", "Going", "Went"], correctAnswer: 0, explanation: "With third person singular subject (He), we use 'goes' in simple present tense", subject: "english", chapter: "Grammar", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-003", text: "Identify the figure of speech: 'The world is a stage.'", options: ["Metaphor", "Simile", "Personification", "Hyperbole"], correctAnswer: 0, explanation: "'The world is a stage' is a metaphor as it directly compares without using 'like' or 'as'", subject: "english", chapter: "Literary Devices", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-004", text: "Choose the correctly spelled word:", options: ["Accommodation", "Acommodation", "Accomodation", "Acomodation"], correctAnswer: 0, explanation: "Accommodation is the correct spelling with double 'c' and double 'm'", subject: "english", chapter: "Spelling", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-005", text: "The antonym of 'Abundant' is:", options: ["Scarce", "Plenty", "Sufficient", "Ample"], correctAnswer: 0, explanation: "Abundant means plentiful, so its antonym is scarce", subject: "english", chapter: "Vocabulary", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-006", text: "Which sentence is in passive voice?", options: ["The letter was written by her", "She wrote a letter", "She is writing a letter", "She has written a letter"], correctAnswer: 0, explanation: "Passive voice: object + was/were + verb + by + subject", subject: "english", chapter: "Grammar", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-007", text: "Complete the idiom: 'To burn the midnight ___'", options: ["Oil", "Lamp", "Candle", "Fire"], correctAnswer: 0, explanation: "'To burn the midnight oil' means to study or work late into the night", subject: "english", chapter: "Idioms and Phrases", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-008", text: "Which of the following is a compound word?", options: ["Sunflower", "Beautiful", "Quickly", "Happiness"], correctAnswer: 0, explanation: "Sunflower = Sun + Flower, a compound word made of two words", subject: "english", chapter: "Word Formation", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-009", text: "Choose the correct preposition: 'She is afraid ___ dogs.'", options: ["Of", "From", "To", "With"], correctAnswer: 0, explanation: "The correct preposition is 'afraid of'", subject: "english", chapter: "Grammar", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-010", text: "A poem praising a person or thing is called:", options: ["Ode", "Sonnet", "Elegy", "Ballad"], correctAnswer: 0, explanation: "An ode is a poem written to praise and glorify a person, object, or event", subject: "english", chapter: "Literary Forms", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-011", text: "Choose the correct synonym of 'Ephemeral':", options: ["Short-lived", "Eternal", "Powerful", "Weak"], correctAnswer: 0, explanation: "Ephemeral means lasting for a very short time", subject: "english", chapter: "Vocabulary", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-012", text: "Fill in the blank: 'Neither the teacher nor the students ___ present.'", options: ["was", "were", "is", "has been"], correctAnswer: 1, explanation: "With 'neither...nor', the verb agrees with the subject closest to it (students - plural)", subject: "english", chapter: "Grammar", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-013", text: "Identify the literary device: 'The wind whispered through the trees.'", options: ["Personification", "Metaphor", "Simile", "Alliteration"], correctAnswer: 0, explanation: "Giving human quality (whispered) to wind is personification", subject: "english", chapter: "Literary Devices", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-014", text: "Choose the correctly spelled word:", options: ["Harassment", "Harasment", "Harrassment", "Harassmant"], correctAnswer: 0, explanation: "Harassment is the correct spelling with one 'r' and double 's'", subject: "english", chapter: "Spelling", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-015", text: "The antonym of 'Eloquent' is:", options: ["Inarticulate", "Fluent", "Persuasive", "Expressive"], correctAnswer: 0, explanation: "Eloquent means fluent and persuasive; its antonym is inarticulate", subject: "english", chapter: "Vocabulary", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-016", text: "Which sentence uses the correct tense?", options: ["I have been working here since 2020", "I am working here since 2020", "I worked here since 2020", "I was working here since 2020"], correctAnswer: 0, explanation: "Present perfect continuous ('have been working') is used with 'since' for ongoing actions", subject: "english", chapter: "Grammar", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-017", text: "Complete the idiom: 'To hit the nail on the ___'", options: ["Head", "Top", "Surface", "Mark"], correctAnswer: 0, explanation: "'To hit the nail on the head' means to describe exactly what is causing a situation", subject: "english", chapter: "Idioms and Phrases", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-018", text: "Which of the following is a prefix?", options: ["Un-", "-ness", "-ly", "-ing"], correctAnswer: 0, explanation: "'Un-' is a prefix added before a root word, while '-ness', '-ly', '-ing' are suffixes", subject: "english", chapter: "Word Formation", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-019", text: "Choose the correct preposition: 'He is proficient ___ English.'", options: ["in", "at", "on", "with"], correctAnswer: 0, explanation: "The correct preposition is 'proficient in'", subject: "english", chapter: "Grammar", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-020", text: "A short story with a moral lesson is called:", options: ["Fable", "Novel", "Biography", "Memoir"], correctAnswer: 0, explanation: "A fable is a short story, typically with animals as characters, conveying a moral", subject: "english", chapter: "Literary Forms", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-021", text: "Choose the correct synonym of 'Candid':", options: ["Frank", "Deceitful", "Vague", "Mysterious"], correctAnswer: 0, explanation: "Candid means truthful and straightforward; frank is its synonym", subject: "english", chapter: "Vocabulary", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-022", text: "Fill in the blank: 'If I ___ you, I would accept the offer.'", options: ["were", "am", "was", "be"], correctAnswer: 0, explanation: "In conditional sentences, 'were' is used for all subjects in the subjunctive mood", subject: "english", chapter: "Grammar", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-023", text: "Identify the figure of speech: 'She sells seashells by the seashore.'", options: ["Alliteration", "Simile", "Metaphor", "Onomatopoeia"], correctAnswer: 0, explanation: "Repetition of the 's' sound at the beginning of words is alliteration", subject: "english", chapter: "Literary Devices", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-024", text: "Choose the correctly spelled word:", options: ["Exaggerate", "Exagerate", "Exxagerate", "Exaggerrate"], correctAnswer: 0, explanation: "Exaggerate is the correct spelling with double 'g' and single 'r'", subject: "english", chapter: "Spelling", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-025", text: "The antonym of 'Arrogant' is:", options: ["Humble", "Proud", "Conceited", "Haughty"], correctAnswer: 0, explanation: "Arrogant means having an exaggerated sense of importance; humble is its opposite", subject: "english", chapter: "Vocabulary", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-026", text: "Which sentence is in active voice?", options: ["The boy threw the ball", "The ball was thrown by the boy", "The ball is thrown", "The ball has been thrown"], correctAnswer: 0, explanation: "Active voice: subject (the boy) performs the action (threw) on the object (the ball)", subject: "english", chapter: "Grammar", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-027", text: "Complete the idiom: 'Actions speak louder than ___'", options: ["Words", "Thoughts", "Deeds", "Promises"], correctAnswer: 0, explanation: "'Actions speak louder than words' means what you do matters more than what you say", subject: "english", chapter: "Idioms and Phrases", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-028", text: "Which of the following is a suffix?", options: ["-ment", "pre-", "un-", "dis-"], correctAnswer: 0, explanation: "'-ment' is a suffix added after a root word to form nouns", subject: "english", chapter: "Word Formation", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-029", text: "Choose the correct preposition: 'The book is divided ___ five chapters.'", options: ["into", "in", "among", "between"], correctAnswer: 0, explanation: "The correct preposition is 'divided into' for parts of a whole", subject: "english", chapter: "Grammar", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-030", text: "A long narrative poem celebrating heroic deeds is called:", options: ["Epic", "Lyric", "Sonnet", "Elegy"], correctAnswer: 0, explanation: "An epic is a long narrative poem celebrating heroic deeds and adventures", subject: "english", chapter: "Literary Forms", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-031", text: "Choose the correct synonym of 'Reluctant':", options: ["Unwilling", "Eager", "Ready", "Willing"], correctAnswer: 0, explanation: "Reluctant means unwilling or hesitant to do something", subject: "english", chapter: "Vocabulary", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-032", text: "Fill in the blank: 'She has been studying ___ morning.'", options: ["since", "for", "from", "by"], correctAnswer: 0, explanation: "'Since' is used with a specific point in time (morning)", subject: "english", chapter: "Grammar", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-033", text: "Identify the literary device: 'The classroom was a zoo.'", options: ["Metaphor", "Simile", "Hyperbole", "Personification"], correctAnswer: 0, explanation: "Direct comparison without 'like' or 'as' makes this a metaphor", subject: "english", chapter: "Literary Devices", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-034", text: "Choose the correctly spelled word:", options: ["Necessary", "Neccessary", "Necesary", "Nessecary"], correctAnswer: 0, explanation: "Necessary is the correct spelling with one 'c' and double 's'", subject: "english", chapter: "Spelling", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-035", text: "The antonym of 'Optimistic' is:", options: ["Pessimistic", "Hopeful", "Positive", "Cheerful"], correctAnswer: 0, explanation: "Optimistic means hopeful and positive; pessimistic is its opposite", subject: "english", chapter: "Vocabulary", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-036", text: "Which sentence contains a dangling modifier?", options: ["Walking home, the rain started", "Walking home, I saw the rain", "While walking home, I felt the rain", "I was walking home when it rained"], correctAnswer: 0, explanation: "In 'Walking home, the rain started', the modifier 'walking home' dangles because rain cannot walk", subject: "english", chapter: "Grammar", difficulty: "hard", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-037", text: "Complete the proverb: 'All that glitters is not ___'", options: ["Gold", "Silver", "Diamond", "Real"], correctAnswer: 0, explanation: "'All that glitters is not gold' means appearances can be deceptive", subject: "english", chapter: "Idioms and Phrases", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-038", text: "Which word is formed by adding a suffix to 'beauty'?", options: ["Beautiful", "Beautify", "Beautician", "All of the above"], correctAnswer: 3, explanation: "All three words can be formed by adding suffixes to 'beauty': -ful, -fy, -ician", subject: "english", chapter: "Word Formation", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-039", text: "Choose the correct article: '___ honest man is respected by all.'", options: ["An", "A", "The", "No article"], correctAnswer: 0, explanation: "'Honest' begins with a silent 'h', so the article 'an' is used", subject: "english", chapter: "Grammar", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-040", text: "A group of lines in a poem is called a:", options: ["Stanza", "Paragraph", "Verse", "Couplet"], correctAnswer: 0, explanation: "A stanza is a grouped set of lines within a poem", subject: "english", chapter: "Literary Forms", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-041", text: "Choose the correct synonym of 'Obsolete':", options: ["Outdated", "Modern", "New", "Advanced"], correctAnswer: 0, explanation: "Obsolete means no longer in use or outdated", subject: "english", chapter: "Vocabulary", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-042", text: "Fill in the blank: 'The committee ___ divided in its opinion.'", options: ["is", "are", "were", "have been"], correctAnswer: 0, explanation: "When the committee acts as a single unit, a singular verb is used", subject: "english", chapter: "Grammar", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-043", text: "Identify the figure of speech: 'I've told you a million times.'", options: ["Hyperbole", "Simile", "Metaphor", "Understatement"], correctAnswer: 0, explanation: "Exaggeration for emphasis (million times) is hyperbole", subject: "english", chapter: "Literary Devices", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-044", text: "Choose the correctly spelled word:", options: ["Embarrass", "Embarass", "Embarras", "Embaras"], correctAnswer: 0, explanation: "Embarrass is the correct spelling with double 'r' and double 's'", subject: "english", chapter: "Spelling", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-045", text: "The antonym of 'Temporary' is:", options: ["Permanent", "Brief", "Short", "Momentary"], correctAnswer: 0, explanation: "Temporary means lasting for a limited time; permanent is its opposite", subject: "english", chapter: "Vocabulary", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-046", text: "Which sentence uses the correct conditional form?", options: ["If I had known, I would have come", "If I have known, I would come", "If I knew, I will come", "If I had known, I will come"], correctAnswer: 0, explanation: "Third conditional uses 'had + past participle' with 'would have'", subject: "english", chapter: "Grammar", difficulty: "hard", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-047", text: "Complete the idiom: 'When in Rome, do as the ___ do'", options: ["Romans", "Natives", "People", "Locals"], correctAnswer: 0, explanation: "'When in Rome, do as the Romans do' means adapt to local customs", subject: "english", chapter: "Idioms and Phrases", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-048", text: "Which of the following is a compound sentence?", options: ["I went home and ate dinner", "Going home, I ate dinner", "After going home, I ate dinner", "I ate dinner at home"], correctAnswer: 0, explanation: "A compound sentence joins two independent clauses with a conjunction (and)", subject: "english", chapter: "Grammar", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-049", text: "Choose the correct conjunction: 'She is smart ___ hardworking.'", options: ["and", "but", "or", "yet"], correctAnswer: 0, explanation: "'And' is used to connect two positive qualities", subject: "english", chapter: "Grammar", difficulty: "easy", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
  { id: "eng-pyq-2025-s2-050", text: "A 14-line poem with a specific rhyme scheme is called:", options: ["Sonnet", "Haiku", "Limerick", "Free verse"], correctAnswer: 0, explanation: "A sonnet is a 14-line poem with a specific rhyme scheme, typically iambic pentameter", subject: "english", chapter: "Literary Forms", difficulty: "medium", bank: "pyq", year: 2025, source: "CUET 2025 Shift 2" },
];
